import express from 'express'; import PDFDocument from 'pdfkit'; const router=express.Router(); router.post('/generate', async (req,res)=>{ const {metrics,riskMetrics,benchmarkData,peerData,topHoldings,commentary,fundName,reportPeriod,fundObjective,brandName}=req.body; res.setHeader('Content-Type','application/pdf'); res.setHeader('Content-Disposition','attachment; filename=factsheet.pdf'); const doc=new PDFDocument({margin:50}); doc.pipe(res); doc.fontSize(24).text(brandName||'AI Reporting Studio'); doc.moveDown(0.5); doc.fontSize(20).text(fundName||'Fund Factsheet'); doc.fontSize(12).fillColor('gray').text(`${reportPeriod||'Monthly'} Factsheet`); doc.moveDown(); doc.fillColor('black').fontSize(14).text('Fund Objective'); doc.fontSize(11).text(fundObjective||'-'); doc.addPage(); doc.fontSize(16).text('Fund Snapshot'); [['Average Return',`${metrics.avg_return.toFixed(2)}%`],['Total Return',`${metrics.total_return.toFixed(2)}%`],['Volatility',`${riskMetrics.volatility.toFixed(2)}%`],['Sharpe Ratio',`${riskMetrics.sharpe_ratio.toFixed(2)}`],['Benchmark Return',`${benchmarkData.benchmark_return.toFixed(2)}%`],['Alpha',`${benchmarkData.alpha.toFixed(2)}%`],['Peer Avg Return',`${peerData.peer_average.toFixed(2)}%`]].forEach(([k,v])=>doc.fontSize(11).text(`${k}: ${v}`)); doc.moveDown(); doc.fontSize(16).text('Top Holdings'); topHoldings.forEach(h=>doc.fontSize(11).text(`• ${h.stock} | ${h.sector} | ${h.return.toFixed(2)}%`)); doc.moveDown(); doc.fontSize(16).text('AI Commentary'); doc.fontSize(11).text(commentary||'No commentary generated.'); doc.moveDown(2); doc.fontSize(8).fillColor('gray').text('Disclaimer: This report has been generated using artificial intelligence (AI) tools based on the data inputs provided and prevailing market sentiment. It is for informational purposes only and does not constitute investment advice.'); doc.end(); }); export default router;